import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyTable, headerActions, headerStrings, breadCrumbActions, mainStageHeaderAction } from "../../utils";
import { routeNamesInventory } from '../../routeNames';
import { priceListActions } from '../actions';
import { priceListStrings } from '../config';
import { TableCell } from '@material-ui/core';


const style = theme => ({
    root: {
        marginTop : 30,
    },
    cell : {
        padding : 5,
        paddingLeft : 10,
    }
})
class _PriceListItems extends Component {
    constructor(props) {
        super(props);
        
        const {dispatch, match} = props;
        this.priceListId = match.params.id;
        headerActions({
            [headerStrings.headerTitle] : "PRICE LIST ITEMS",
            [headerStrings.backButtonAction] : ()=>{},
        })(dispatch);
        breadCrumbActions.addToBreadCrumb([
            {name : "List Items", path : routeNamesInventory.priceListItem_ + this.priceListId}
        ])(dispatch);
        mainStageHeaderAction({})(dispatch);    
        this.initialiseComponent();
    }
    initialiseComponent(){
        const {
            dispatch,
            [priceListStrings.stockCategories] : stockCategories,
            [priceListStrings.itemPackages] : itemPackages,
        } = this.props;
        priceListActions.getPriceListItems(this.priceListId)(dispatch);
        if(!stockCategories) 
            priceListActions.getStockCategories()(dispatch);
        if(!itemPackages) priceListActions.getItemPackages()(dispatch);
    }
    cellMapFormat = ({row, cellMap}) => {
        const {
            classes,
            [priceListStrings.stockCategories] : stockCategories,
            [priceListStrings.itemPackages] : itemPackages,
        } = this.props;

        switch(cellMap){
            case "item" : return <TableCell className={classes.cell}>
                {row.item.name}
            </TableCell>
            case "category" : 
                const {item : categoryItems} = stockCategories.getFirstObjectByPropValue("_id", row.item.categoryId) || {};
                let category = null;
                if(categoryItems)
                    category = categoryItems.name 
                return <TableCell className={classes.cell}>
                    {category}
                </TableCell>
            case "cost" : 
            case "brand" : 
                return <TableCell className={classes.cell}>
                    {row.item.brand}
                </TableCell>
            case "prices" : 
                return <TableCell className={classes.cell}>
                    {row.packages && row.packages.map((item, index)=>{
                        let packageName = null;
                        const {packageId, price} = item;
                        const {item : packageItem} = itemPackages.getFirstObjectByPropValue("_id", packageId) || {};
                        if(packageItem) packageName = packageItem.name;
                        return <div><strong>{packageName}: </strong>{price}</div>
                    })}
                </TableCell>
            default : return <TableCell className={classes.cell}>

            </TableCell>
        }
    }
    render() {
        const {
            classes,
            [priceListStrings.pricelistItems] : pricelistItems,
        } = this.props;
        return (
            <div className={classes.root}>
                <MyTable
                    header={["Item/Product", "Brand", "Category", "Avg. Cost", "Prices"]}
                    dataMap={["item", "brand", "category", "cost", "prices"]}
                    data={pricelistItems}
                    CellMap={this.cellMapFormat.bind(this)}
                    />
            </div>
        );
    }
}


_PriceListItems.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({priceListReducer}) => ({
    [priceListStrings.pricelistItems] : priceListReducer[priceListStrings.pricelistItems],
    [priceListStrings.stockCategories] : priceListReducer[priceListStrings.stockCategories],
    [priceListStrings.itemPackages] : priceListReducer[priceListStrings.itemPackages],
})


export const PriceListItems = connect(mapStateToProps)(withStyles(style)(_PriceListItems));
export {PriceListItems as default}